1	const PROCESSING_FEE = 5;
2	
3	interface Item {
4	  type: string;
5	  material: string;
6	  enchantment: number;
7	  cursed: boolean;
8	}
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const CURSED_SURCHARGE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
25	const HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
26	
27	const FIRST_INSURANCE_RATE = 0.1;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_MIN_YEARS = 2;
30	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
31	
32	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	const itemPremium = (item: Item): number => {
37	  const base = basePremium(item);
38	  const curseSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
39	  const enchantmentSurcharge =
40	    item.enchantment >= HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD
41	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
42	      : 0;
43	  return base + curseSurcharge + enchantmentSurcharge;
44	};
45	
46	const componentBlockPremium = (type: string, count: number): number =>
47	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
48	
49	const countByType = (items: Item[]): Record<string, number> =>
50	  items.reduce<Record<string, number>>((counts, item) => {
51	    counts[item.type] = (counts[item.type] ?? 0) + 1;
52	    return counts;
53	  }, {});
54	
55	const componentsPremium = (components: Item[]): number =>
56	  Object.entries(countByType(components)).reduce(
57	    (sum, [type, count]) => sum + componentBlockPremium(type, count),
58	    0
59	  );
60	
61	const itemsPremium = (items: Item[]): number => {
62	  const components = items.filter(isComponent);
63	  const nonComponents = items.filter((item) => !isComponent(item));
64	  const mainPremium = nonComponents.reduce(
65	    (sum, item) => sum + itemPremium(item),
66	    0
67	  );
68	  return mainPremium + componentsPremium(components);
69	};
70	
71	const INSURANCE_VALUES: Record<string, number> = {
72	  sword: 1000,
73	  amulet: 600,
74	  staff: 800,
75	  potion: 400,
76	  rune: 250,
77	  moonstone: 250,
78	};
79	
80	const DEDUCTIBLE = 100;
81	const HIGH_ENCHANTMENT_THRESHOLD = 8;
82	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
83	const CAP_MULTIPLIER = 2;
84	
85	const isHighEnchantment = (item: Item | undefined): boolean =>
86	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
87	
88	const reimbursableAmount = (policyItem: Item | undefined, damageAmount: number): number =>
89	  isHighEnchantment(policyItem)
90	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
91	    : damageAmount;
92	
93	const insuranceValue = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;
94	
95	const totalInsuranceValue = (items: Item[]): number =>
96	  items.reduce((sum, item) => sum + insuranceValue(item), 0);
97	
98	export const claim = (
99	  policy: { items: Item[] },
100	  damages: { itemType: string; amount: number }[],
101	  remainingCap?: number
102	): { payout: number; remainingCap: number } => {
103	  const cap = remainingCap ?? totalInsuranceValue(policy.items) * CAP_MULTIPLIER;
104	  const uncappedPayout = damages.reduce((sum, damage) => {
105	    const policyItem = policy.items.find((item) => item.type === damage.itemType);
106	    const reimbursement = reimbursableAmount(policyItem, damage.amount);
107	    return sum + Math.max(0, reimbursement - DEDUCTIBLE);
108	  }, 0);
109	  const payout = Math.floor(Math.min(uncappedPayout, cap));
110	  return { payout, remainingCap: cap - payout };
111	};
112	
113	export const quote = (
114	  customer: { yearsWithMHPCO: number },
115	  items: Item[],
116	  isFollowUp: boolean
117	): number => {
118	  for (const item of items) {
119	    if (!(item.type in BASE_PREMIUMS)) {
120	      throw new Error(`Unknown item type: ${item.type}`);
121	    }
122	  }
123	  const premium = itemsPremium(items);
124	  const policyBasePremium = items.reduce((sum, item) => sum + basePremium(item), 0);
125	  const firstInsurance = policyBasePremium * FIRST_INSURANCE_RATE;
126	  const loyaltyDiscount =
127	    customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
128	      ? policyBasePremium * LOYALTY_DISCOUNT_RATE
129	      : 0;
130	  const followUpDiscount = isFollowUp
131	    ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE
132	    : 0;
133	  return Math.ceil(premium + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
134	};
